module FP_Div_Top (
  clk,
  rstn,
  data_a,
  data_b,
  result
)
;
input clk;
input rstn;
input [31:0] data_a;
input [31:0] data_b;
output [31:0] result;
wire VCC;
wire GND;
  \(FP_Div)/(FP_Div_Top)  FP_Div_inst (
    .clk(clk),
    .rstn(rstn),
    .data_a(data_a[31:0]),
    .data_b(data_b[31:0]),
    .result(result[31:0])
);
  VCC VCC_cZ (
    .V(VCC)
);
  GND GND_cZ (
    .G(GND)
);
  GSR GSR (
    .GSRI(VCC) 
);
endmodule /* FP_Div_Top */
